import nextTypescript from "eslint-config-next/typescript";
import nextCoreWebVitals from "eslint-config-next/core-web-vitals";
import { dirname } from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const eslintConfig = [...nextTypescript, ...nextCoreWebVitals, {
  ignores: ["node_modules/**", ".next/**", "out/**", "build/**", "next-env.d.ts"],
  rules: {
    "react/no-unescaped-entities": "off",
    "@next/next/no-page-custom-font": "off",
    "@next/next/no-img-element": "warn",
    "@typescript-eslint/no-explicit-any": "off",
    "@typescript-eslint/no-unused-vars": "warn",
    "react-hooks/rules-of-hooks": "warn",
    "react-hooks/exhaustive-deps": "warn",
    "react-hooks/set-state-in-effect": "warn"
  }
}];

export default eslintConfig;

const mongoose = require('mongoose');

const destinationSchema = new mongoose.Schema({
  name: { type: String, required: true },
  country: { type: String, required: true },
  city: { type: String },
  description: { type: String },
  category: { type: String, enum: ['beach', 'mountain', 'city', 'cultural', 'adventure', 'relaxation'] },
  bestTimeToVisit: { type: String },
  averageCost: {
    low: { type: Number, default: 0 },
    medium: { type: Number, default: 0 },
    high: { type: Number, default: 0 }
  },
  activities: [{ type: String }],
  imageUrl: { type: String },
  coordinates: {
    lat: { type: Number },
    lng: { type: Number }
  },
  createdAt: { type: Date, default: Date.now }
});

module.exports = mongoose.model('Destination', destinationSchema);

const mongoose = require('mongoose');

const itineraryItemSchema = new mongoose.Schema({
  day: { type: Number, required: true },
  time: { type: String, required: true }, // e.g., "09:00"
  activity: { type: String, required: true },
  location: { type: String },
  description: { type: String },
  duration: { type: String }, // e.g., "2 hours"
  cost: { type: Number, default: 0 },
  category: { type: String, enum: ['sightseeing', 'food', 'shopping', 'adventure', 'relaxation', 'transport'] },
  coordinates: {
    lat: { type: Number },
    lng: { type: Number }
  }
});

const itinerarySchema = new mongoose.Schema({
  userId: { type: String, required: true }, // Changed from ObjectId to String for mock users
  tripId: { type: String, required: true },
  title: { type: String, required: true },
  destinations: [{ type: String }], // Array of destination names
  startDate: { type: Date, required: true },
  endDate: { type: Date, required: true },
  budget: {
    total: { type: Number, required: true },
    currency: { type: String, default: 'USD' },
    breakdown: {
      flights: { type: Number, default: 0 },
      hotels: { type: Number, default: 0 },
      activities: { type: Number, default: 0 },
      food: { type: Number, default: 0 },
      miscellaneous: { type: Number, default: 0 }
    }
  },
  preferences: {
    pace: { type: String, enum: ['relaxed', 'moderate', 'intense'], default: 'moderate' },
    interests: [{ type: String }],
    dietaryRestrictions: [{ type: String }],
    accessibility: { type: Boolean, default: false }
  },
  itinerary: [itineraryItemSchema],
  flights: [{
    departure: {
      airport: { type: String },
      date: { type: Date },
      time: { type: String }
    },
    arrival: {
      airport: { type: String },
      date: { type: Date },
      time: { type: String }
    },
    airline: { type: String },
    flightNumber: { type: String },
    cost: { type: Number },
    duration: { type: String }
  }],
  hotels: [{
    name: { type: String },
    location: { type: String },
    checkIn: { type: Date },
    checkOut: { type: Date },
    cost: { type: Number },
    rating: { type: Number },
    amenities: [{ type: String }]
  }],
  recommendations: [{
    type: { type: String, enum: ['destination', 'activity', 'restaurant', 'attraction'] },
    title: { type: String },
    description: { type: String },
    reason: { type: String }, // Why recommended based on personality
    cost: { type: Number },
    rating: { type: Number }
  }],
  status: { type: String, enum: ['draft', 'confirmed', 'completed'], default: 'draft' },
  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now }
});

// Update the updatedAt field before saving
// itinerarySchema.pre('save', function(next) {
//   this.updatedAt = new Date();
//   next();
// });

module.exports = mongoose.model('Itinerary', itinerarySchema);

const mongoose = require('mongoose');

const itineraryItemSchema = new mongoose.Schema({
  type: { type: String, enum: ['flight', 'stay', 'activity'], required: true },
  time: { type: String, required: true },
  title: { type: String, required: true },
  meta: { type: String, default: '' }
}, { _id: false });

const daySchema = new mongoose.Schema({
  label: { type: String, required: true },
  items: [itineraryItemSchema]
}, { _id: false });

const tripSchema = new mongoose.Schema({
  id: { type: String, unique: true },
  title: { type: String, required: true },
  dates: { type: String, required: true },
  summary: { type: String, default: '' },
  locations: [{ type: String }],
  vibeTag: { type: String, default: '' },
  budgetHint: { type: String, default: '' },
  itinerary: [daySchema],
  budget: {
    currency: { type: String, default: 'EUR' },
    roughTotal: { type: Number, default: 0 }
  },
  created_at: { type: Date, default: Date.now },
  updated_at: { type: Date, default: Date.now }
});

// Auto-update timestamp
tripSchema.pre('save', function(next) {
  this.updated_at = new Date();
  next();
});

module.exports = mongoose.model('Trip', tripSchema);

