    if (!message) {
      return res.status(400).json({
        success: false,
        error: 'Message is required'
      });
    }

    // Call ML API
    const response = await axios.post(
      `${ML_API_URL}/api/chat`,
      {
        message,
        trip_context
      },
      {
        headers: {
          'Authorization': req.headers.authorization || '',
          'Content-Type': 'application/json'
        },
        timeout: 15000
      }
