const getItemIcon = t => ({ flight:Plane, stay:Hotel, food:Utensils, activity:Camera }[t] || MapPin);
const getTypeColor = t => ({ flight:"#3b82f6", stay:"#8b5cf6", food:"#f97316", activity:"#10b981" }[t] || "#64748b");
