  iconSize:[30,30], iconAnchor:[15,15],
});

// ÔöÇÔöÇÔöÇ Map controller ÔÇö flies to selected place & fits bounds ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function MapController({ markers, flyTo }) {
  const map = useMap();
  useEffect(() => {
    if (flyTo) map.flyTo(flyTo, 15, { duration: 1.2 });
  }, [flyTo, map]);
  useEffect(() => {
    const valid = markers.filter(m => m.coords);
    if (valid.length === 0) return;
    if (valid.length === 1) { map.flyTo(valid[0].coords, 13, { duration: 1 }); return; }
    const bounds = L.latLngBounds(valid.map(m => m.coords));
    if (bounds.isValid()) map.fitBounds(bounds, { padding:[70,70], maxZoom:14, duration:1 });
  }, [markers.length]);
  return null;
}

// ÔöÇÔöÇÔöÇ Safe image with fallback ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function SafeImg({ src, alt, className, city = "travel" }) {
